import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as d,d as c}from"./app-505788a4.js";const i={},t=c('<p>Web应用程序是使用<code>HTTP</code>协议传输数据的。<strong><code>HTTP</code>协议是无状态的协议。一旦数据交换完毕，客户端与服务器端的连接就会关闭，再次交换数据需要建立新的连接。这就意味着服务器无法从连接上跟踪会话</strong>。要跟踪该会话，必须引入一种状态保持机制。</p><h2 id="状态保持" tabindex="-1"><a class="header-anchor" href="#状态保持" aria-hidden="true">#</a> 状态保持</h2><ul><li><p>修改<code>Http</code>协议，使得它支持状态保持(难做到)</p></li><li><p><code>Cookies</code>：通过客户端来保持状态信息</p><ul><li><code>Cookie</code>是服务器发给客户端的特殊信息</li><li><code>Cookie</code>是以文本的方式保存在客户端，每次请求时都带上它</li></ul></li><li><p><code>Session</code>：通过服务器端来保持状态信息</p><ul><li><p><code>Session</code>是服务器和客户端之间的一系列的交互动作</p></li><li><p>服务器为每个客户端开辟内存空间，从而保持状态信息</p></li><li><p>由于需要客户端也要持有一个标识(<code>id</code>)，因此，也要求服务器端和客户端传输该标识，</p></li><li><p>标识(<code>id</code>)可以借助<code>Cookie</code>机制或者其他的途径来保存</p></li></ul></li></ul><h2 id="cookie机制" tabindex="-1"><a class="header-anchor" href="#cookie机制" aria-hidden="true">#</a> <code>COOKIE</code>机制</h2><blockquote><p><code>Cookie</code>，有时也用其复数形式<code>Cookies</code>，指某些网站为了辨别用户身份、进行<code>session</code>跟踪而储存在用户本地终端上的数据（通常经过加密）。</p></blockquote><p>由于<em>HTTP</em>是一种无状态的协议，服务器单从网络连接上无从知道客户身份。怎么办呢？就<strong>给客户端们颁发一个通行证吧，每人一个，无论谁访问都必须携带自己通行证。这样服务器就能从通行证上确认客户身份了。这就是Cookie的工作原理</strong>。</p><p><code>Cookie</code>是由服务器端生成，发送给<code>User-Agent</code>（一般是浏览器），浏览器会将<code>Cookie</code>的<code>key/value</code>保存到某个目录下的文本文件内，下次请求同一网站时就发送该<code>Cookie</code>给服务器（前提是浏览器设置为启用cookie）。<code>Cookie</code>名称和值可以由服务器端开发自己定义，这样服务器可以知道该用户是否是合法用户以及是否需要重新登录等。服务器可以利用<code>Cookies</code>包含信息的任意性来筛选并经常性维护这些信息，以判断在<code>HTTP</code>传输中的状态。</p><p><code>Cookie</code>是存储在浏览器中的一段纯文本信息，建议不要存储敏感信息,如密码。</p><p><strong><code>Cookie</code>具有不可跨域名性</strong>。根据<em>Cookie</em>规范，浏览器访问<em>Google</em>只会携带<em>Google</em>的<code>Cookie</code>，而不会携带<em>Baidu</em>的<code>Cookie</code>。<em>Google</em>也只能操作<em>Google</em>的<code>Cookie</code>，而不能操作Baidu的<code>Cookie</code>。</p><h3 id="基本特点" tabindex="-1"><a class="header-anchor" href="#基本特点" aria-hidden="true">#</a> 基本特点</h3><ul><li><p><code>Cookie</code>以键值对<code>Key-Value</code>形势进行信息的存储,只能保存字符串对象，不能保存对象类型</p></li><li><p><code>Cookie</code>基于域名安全，不同域名的<code>Cookie</code>是不能互相访问的</p></li><li><p><code>Cookie</code>保存在客户端,需要客户端浏览器的支持，<strong>缺点</strong>：浏览器用户可能会禁用<code>Cookie</code></p></li></ul><h2 id="session机制" tabindex="-1"><a class="header-anchor" href="#session机制" aria-hidden="true">#</a> <code>SESSION</code>机制</h2><p>如果说 <strong><code>Cookie</code>机制是通过检查客户身上的“通行证”来确定客户身份的话，那么<code>Session</code>机制就是通过检查服务器上的“客户明细表”来确认客户身份。<code>Session</code>相当于程序在服务器上建立的一份客户档案，客户来访的时候只需要查询客户档案表就可以了。</strong></p><p>每次客户端发送请求，服务端都检查是否含有<code>sessionId</code>。</p><p>如果有，则根据<code>sessionId</code>检索出<code>session</code>并处理；如果没有，则创建一个<code>session</code>，并绑定一个不重复的<code>sessionId</code>。</p><h3 id="基本特点-1" tabindex="-1"><a class="header-anchor" href="#基本特点-1" aria-hidden="true">#</a> 基本特点</h3><ul><li><p>状态信息保存在服务器端。这意味着安全性更高，可以存储敏感、重要的信息，支持更多字节，<strong>缺点</strong>：<code>Session</code>共享问题</p></li><li><p>通过类似与<code>Hashtable</code>的数据结构来保存，能支持任何类型的对象(<em><code>session</code>中可含有多个对象</em>)</p></li><li><p>保存会话id的技术,依赖于 <code>Cookie</code>。默认情况下在客户端与服务器端之间通过<code>cookie</code>方式传递 <code>SeesionId</code></p></li></ul><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>两种状态跟踪机制的比较</p><table><thead><tr><th></th><th><code>Cookie</code></th><th><code>Session</code></th></tr></thead><tbody><tr><td>存储位置</td><td>保持在客户端</td><td>保存在服务器端</td></tr><tr><td>存储类型</td><td>只能保持字符串对象</td><td>支持各种类型对象</td></tr><tr><td>实现机制</td><td>通过过期时间值区分<code>Cookie</code>的类型</td><td>需要<code>SeesionId</code>来维护与客户端的通信</td></tr><tr><td></td><td>会话<code>Cookie</code>——负数表示关闭浏览器销毁<code>Cookie</code></td><td><code>Cookie</code>(默认)</td></tr><tr><td></td><td>普通<code>Cookie</code>——正数是设置的销毁时间，单位是秒</td><td>表单隐藏字段</td></tr><tr><td></td><td>不支持<code>Cookie</code>——0表示立即销毁<code>Cookie</code></td><td>*<code>url</code>*重写</td></tr></tbody></table>',20),s=[t];function r(a,l){return o(),d("div",null,s)}const h=e(i,[["render",r],["__file","cookie与session的对比-3f70ac0b.html.vue"]]);export{h as default};
